class Solution {
public:
    string countOfAtoms(string formula) {
        int n = formula.size();
        unordered_map<string, int> count;
        for (int i = 0; i < n; ) {
            if (formula[i] == '(') {
                int j = i + 1, cnt = 0;
                while (cnt != 0 || formula[j] != ')') {
                    if (formula[j] == '(') cnt++;
                    if (formula[j] == ')') cnt--;
                    j++;
                }
                string sub = formula.substr(i + 1, j - i - 1);
                int k = j + 1;
                while (k < n && isdigit(formula[k])) k++;
                int times = 1;
                if (k > j) times = stoi(formula.substr(j, k - j));
                unordered_map<string, int> subCount = countOfAtoms(sub);
                for (auto& pair : subCount) {
                    count[pair.first] += pair.second * times;
                }
                i = k;
            } else {
                int j = i + 1;
                while (j < n && islower(formula[j])) j++;
                string atom = formula.substr(i, j - i);
                i = j;
                int k = i;
                while (k < n && isdigit(formula[k])) k++;
                int times = 1;
                if (k > i) times = stoi(formula.substr(i, k - i));
                count[atom] += times;
                i = k;
            }
        }
        stringstream ss;
        for (auto& pair : count) {
            ss << pair.first;
            if (pair.second > 1) ss << pair.second;
        }
        return ss.str();
    }
};
